item.content:encoded:
.tp-title-wrap {
    display: none !important;
}

.masthead:not(.side-header).full-height .header-bar .main-nav > li > a, .masthead:not(.side-header) .header-bar .main-nav > li > a {
   max-width: 125px !important;
}
 .bg-on .project-list-media {
  padding: 0px !important;
}
.post.bg-on {background-color:#ffffff}
.post .entry-title a {
  display: initial;
  font-weight: bold !important;
	font-size: 30px !important;
}

.inline-header.center .main-nav {
  -ms-flex-pack: center;
  -ms-justify-content: center;
  justify-content: right !important; margin-right:0px
}

section#block-2.widget.widget_block.wf-cell.wf-1-1 a span {margin:0px 20px; text-decoration:none !important}

section#block-2.widget {text-align:center !important; }
.footer .widget a {text-decoration:none !important}
#rev_slider_8_1_wrapper .hebe.tparrows::before {
	color: rgba(51, 82, 100,0.5) !important;}

wp:postmeta.wp:meta_value:
input[type="text"], .widget_search input[type="text"].searchform-s, input[type="search"], input[type="tel"], input[type="url"], input[type="email"], input[type="number"], input[type="date"], input[type="range"], input[type="password"], select, textarea, .wpcf7-number, .woocommerce div.elementor .the7-elementor-widget form.cart table.variations td.value select, .the7-elementor-product-comments .elementor-field-textual, .elementor-field-group .elementor-field-textual, .elementor-field-group .elementor-select-wrapper select {
  color: #274d60;
  font-size: 18px !important;
  border-right-width: 0px !important;
border-bottom: 3px solid !important;
  border-left-width: 0px !important;
  padding: var(--the7-top-input-padding) var(--the7-right-input-padding) var(--the7-bottom-input-padding) var(--the7-left-input-padding);
  border-color:
#274d60;
    border-top-color: rgb(39, 77, 96);
  background-color: transparent;
  border-radius: var(--the7-input-border-radius);
  box-shadow: var(--the7-form-shadow);
  transition:
all 0.3s ease;
  border-top:
0px;
    border-top-style: none;
}

input[type="submit"] {
  position: relative;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  text-decoration:
none;
  white-space:
nowrap;
  -webkit-tap-highlight-color: transparent;
  background-color: #B5B5B0 !important;
  font-size: 30px !important;
  font-weight: normal !important;
  padding:
15px 100px !important;
  color: #274d60 !important;
}

#main {
  padding-bottom: 200px;
}
@media screen and (max-width: 768px) {
  #main {
    padding-bottom: 0px;
  }
}
.fancy-header {
  background-image: none;
  background-repeat: no-repeat;
  background-position: center center;
  background-size: cover;
  background-color: #ffffff;
}
.mobile-false .fancy-header {
  background-attachment: scroll;
}
.fancy-header .wf-wrap {
  min-height: 100px;
  padding-top: 0px;
  padding-bottom: 0px;
}
.fancy-header .fancy-title {
  font-size: 24px;
  line-height: 36px;
  color: #335264;
  text-transform: none;
}
.fancy-header .fancy-subtitle {
  font-size: 18px;
  line-height: 26px;
  color: #ffffff;
  text-transform: none;
}
.fancy-header .breadcrumbs {
  color: #ffffff;
}
.fancy-header-overlay {
  background: rgba(0,0,0,0.5);
}
@media screen and (max-width: 778px) {
  .fancy-header .wf-wrap {
    min-height: 70px;
  }
  .fancy-header .fancy-title {
    font-size: 30px;
    line-height: 38px;
  }
  .fancy-header .fancy-subtitle {
    font-size: 20px;
    line-height: 28px;
  }
  .fancy-header.breadcrumbs-mobile-off .breadcrumbs {
    display: none;
  }
  #fancy-header > .wf-wrap {
    flex-flow: column wrap;
    align-items: center;
    justify-content: center;
    padding-bottom: 0px !important;
  }
  .fancy-header.title-left .breadcrumbs {
    text-align: center;
    float: none;
  }
  .breadcrumbs {
    margin-bottom: 10px;
  }
  .breadcrumbs.breadcrumbs-bg {
    margin-top: 10px;
  }
  .fancy-header.title-right .breadcrumbs {
    margin: 10px 0 10px 0;
  }
  #fancy-header .hgroup,
  #fancy-header .breadcrumbs {
    text-align: center;
  }
  .fancy-header .hgroup {
    padding-bottom: 5px;
  }
  .breadcrumbs-off .hgroup {
    padding-bottom: 5px;
  }
  .title-right .hgroup {
    padding: 0 0 5px 0;
  }
  .title-right.breadcrumbs-off .hgroup {
    padding-top: 5px;
  }
  .title-left.disabled-bg .breadcrumbs {
    margin-bottom: 0;
  }
}

